import{_ as r,o as t,c as a,ae as n}from"./chunks/framework.D6sYw4vw.js";const d=JSON.parse('{"title":"主页","description":"","frontmatter":{"home":true,"icon":"home","title":"主页","heroImage":"/logo.svg","bgImage":"https://theme-hope-assets.vuejs.press/bg/6-light.svg","bgImageDark":"https://theme-hope-assets.vuejs.press/bg/6-dark.svg","bgImageStyle":{"background-attachment":"fixed"},"heroText":"奔向智慧能源新时代","tagline":"Heading Towards a New Era of Smart Energy","copyright":"版权所有 © 2019-2023 Ai4Energy","footer":"<div><span><a href=\\"https://beian.miit.gov.cn/\\" target=\\"_blank\\">陕 ICP 备 19000424 号 -2</a></span>|<span><a href=\\"http://www.beian.gov.cn/portal/registerSystemInfo?recordcode=61010302001034\\" target=\\"_blank\\"><img src=\\"/assets/image/beianicon.png\\">陕公网安备 61010302001034 号</a></span></div>"},"headers":[],"relativePath":"index.md","filePath":"index.md","lastUpdated":1773480129000}'),o={name:"index.md"};function i(s,e,l,g,p,h){return t(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="ai4energy-致力于发展人工智能在能源领域的应用" tabindex="-1">Ai4Energy: 致力于发展人工智能在能源领域的应用 <a class="header-anchor" href="#ai4energy-致力于发展人工智能在能源领域的应用" aria-label="Permalink to &quot;Ai4Energy: 致力于发展人工智能在能源领域的应用&quot;">​</a></h1><p>我们致力于发展人工智能在能源领域的应用，包括从微分代数方程（DAEs）到运筹学（OR），以及机器学习（深度学习、强化学习）等。</p><p>我们项目实践方面目前主要是能源系统的建模、仿真、优化与控制（DAEs 和 OR），以期为能源系统优化设计、优化运行提供基础的软件支撑方案。在机器学习方面则主要探索新方法的应用。项目基于强大的 <a href="https://julialang.org/" target="_blank" rel="noreferrer">Julia</a> 生态构建。针对优化设计问题，主要发展综合能源系统优化问题的建模与求解。针对优化运行问题，则开展仿真引擎、参数识别、模型预测控制方面的开发工作。</p><p>我们也开设了相关研究生课程，请访问 <a href="https://enpocourses.github.io/enpo811203/" target="_blank" rel="noreferrer">智慧能源：从概念到实践</a> 获取更多相关信息。</p><h2 id="核心能力" tabindex="-1">核心能力 <a class="header-anchor" href="#核心能力" aria-label="Permalink to &quot;核心能力&quot;">​</a></h2><ul><li><p><strong>能源系统仿真引擎</strong>。<a href="https://github.com/ai4energy/Ai4EMetaPSE.jl" target="_blank" rel="noreferrer">元流程仿真引擎 Ai4EMetaPSE</a>，采用基于方程的面向对象建模，基于微分代数方程（DAE），对能源系统组件进行建模，用以对能源系统进行稳态、动态仿真。能够处理连续时间及离散事件问题。</p></li><li><p><strong>能源系统优化引擎</strong>。基于分等级组件化建模方法，使用 <a href="https://github.com/jump-dev/JuMP.jl" target="_blank" rel="noreferrer">JuMP.jl</a> 等优化包处理能源系统优化设计问题。</p></li><li><p><strong>能源系统模型预测控制</strong>。基于仿真引擎，利用优化引擎进行参数辨识（模型校准），开发能源系统模型预测控制软件。我们已经写了一个最优控制包 <a href="https://github.com/ai4energy/OptControl.jl" target="_blank" rel="noreferrer">OptControl</a>，相应的文档请点击 <a href="https://ai4energy.github.io/OptControl.jl/dev/" target="_blank" rel="noreferrer">这里</a>。</p></li><li><p><strong>可再生能源组件库</strong>。适用于综合能源系统仿真的 <a href="https://github.com/ai4energy/Ai4EComponentLib.jl" target="_blank" rel="noreferrer">可再生能源组件库（renewable energy library）</a>，持续更新中。</p></li><li><p><strong>综合能源系统虚拟仿真实验室</strong>。适用于综合能源系统仿真的 <a href="https://github.com/ai4energy/Ai4ELab" target="_blank" rel="noreferrer">综合能源系统虚拟仿真实验室</a>，持续更新中。</p></li><li><p><strong>机器学习方法的应用</strong>。</p></li><li><p><strong>智慧能源管理信息系统</strong>。</p></li></ul>',6)])])}const c=r(o,[["render",i]]);export{d as __pageData,c as default};
